from typing import List
from collections import Counter

def top_k_frequent(nums: List[int], k: int) -> List[int]:
    count = Counter(nums)
    return sorted(sorted(count.keys(), key=lambda x: -count[x])[:k])

from typing import List
from collections import Counter
import heapq

def top_k_frequent(nums: List[int], k: int) -> List[int]:
    count = Counter(nums)
    # Use a min-heap of size k (keep the k most frequent)
    heap = []
    for num, freq in count.items():
        heapq.heappush(heap, (freq, num))
        if len(heap) > k:
            heapq.heappop(heap)
    return sorted(num for freq, num in heap)
